{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-pump-update-plus-separator-placeholder-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "summary": "当前围绕已选中的 Booster Pump、Product Separator 及其相关已选流股生成候选提案，重点处理泵出口压力目标无效、泵效率超范围、分离器固定压力模式缺少操作压力目标，以及分离器液相出口未接下游这一组局部问题。",
  "answers": [
    {
      "summary": "建议仅在当前已选中的 pump-13、separator-10 和 separator-liquid-92 上提交最小候选补丁：修正泵的局部参数、为分离器补充缺失的固定压力占位参数，并把未连接液相出口标记为待确认的下游连接占位；由于下游对象缺失，拓扑部分只能给出占位而不能直接指向具体接收方。",
      "issues": [
        {
          "title": "泵出口压力目标低于入口压力且效率超范围",
          "details": "pump-13 的 outlet_pressure_target_kpa=150 低于入口流股 feed-92 的 200 kPa，且 efficiency_percent=109 超出推荐范围。",
          "citations": [
            "diag-2",
            "diag-4",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "title": "固定压力模式分离器缺少操作压力目标",
          "details": "separator-10 处于 fixed pressure_mode，但未提供 operating pressure target。",
          "citations": [
            "diag-3",
            "flowdoc-unit-2"
          ]
        },
        {
          "title": "分离器液相出口未连接且下游选择依赖当前工况",
          "details": "separator-liquid-92 当前没有下游 consumer 或 export sink，且其路由仍依赖当前泵出口与分离器压力上下文，因此只能提出连接占位而不能指定实际目标对象。",
          "citations": [
            "diag-1",
            "diag-5",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "修正 Booster Pump 的局部参数到可审查范围",
          "target": {
            "type": "unit",
            "id": "pump-13"
          },
          "rationale": "当前泵的出口目标压力低于已知入口压力，直接触发无效诊断；同时效率参数超出推荐范围。基于现有证据，可提交仅作用于 pump-13 的最小参数修正候选，其中出口目标压力采用高于已知 200 kPa 入口压力的占位值，避免凭空断定最终设计点。",
          "patch": {
            "parameter_updates": {
              "efficiency_percent": 100
            },
            "parameter_placeholders": {
              "outlet_pressure_target_kpa": {
                "constraint": "> 200",
                "reason": "must exceed inlet stream feed-92 pressure_kpa=200 to satisfy pump pressure rise direction"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "diag-4",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Product Separator 固定压力模式补充操作压力占位",
          "target": {
            "type": "unit",
            "id": "separator-10"
          },
          "rationale": "separator-10 已配置为 fixed 压力模式，但缺少必需的操作压力目标。现有证据不足以唯一确定数值，因此建议添加局部参数占位而不强行指定固定压力值。",
          "patch": {
            "parameter_placeholders": {
              "operating_pressure_target_kpa": {
                "constraint": "required when pressure_mode = fixed",
                "reason": "missing required fixed-pressure operating target"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-2"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Separator Liquid 92 添加待确认的下游连接占位",
          "target": {
            "type": "stream",
            "id": "separator-liquid-92"
          },
          "rationale": "该流股当前未连接，导致无效拓扑；但请求中没有任何现成的下游单元或导出端对象可供直接连接，且诊断明确提示其路由依赖当前泵出口和分离器压力上下文，因此只能给出待确认的连接占位。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "separator-liquid-92",
              "expected_connection": "downstream_consumer_or_export_sink",
              "required": true,
              "reason": "stream is currently disconnected and no evidenced downstream target is present in the request"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "diag-5",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "confidence": 0.88,
      "citations": [
        "diag-2",
        "diag-3",
        "diag-1",
        "flowdoc-unit-1",
        "flowdoc-unit-2",
        "flowdoc-stream-3",
        "snapshot-1"
      ]
    }
  ],
  "citations": [
    "diag-2",
    "diag-3",
    "diag-1",
    "diag-4",
    "diag-5",
    "flowdoc-unit-1",
    "flowdoc-unit-2",
    "flowdoc-stream-1",
    "flowdoc-stream-3",
    "snapshot-1"
  ]
}
